SELECT * FROM b_inbound_record


        AND (INSTR(material_code, #{query.searchWord}) OR INSTR(material_name, #{query.searchWord}) OR INSTR(batch_no, #{query.searchWord}))


        AND material_id = #{query.materialId}


        AND inbound_type = #{query.inboundType}


        AND project_id = #{query.projectId}


        AND deleted_flag = #{query.deletedFlag}


ORDER BY inbound_record_id DESC
